#include <stdio.h>

int main() {
    FILE *fp;
    char buffer[100];

    // Create and write to file
    fp = fopen("test.txt", "w");
    if (fp == NULL) {
        printf("Error creating file\n");
        return 1;
    }
    fprintf(fp, "Sequential access demo");
    fclose(fp);

    // Sequential read
    fp = fopen("test.txt", "r");
    while (fgets(buffer, 100, fp) != NULL) {
        printf("%s", buffer);
    }
    fclose(fp);

    // Direct access with fseek
    fp = fopen("test.txt", "r");
    fseek(fp, 9, SEEK_SET);  // Seek to position 9
    fgets(buffer, 10, fp);
    printf("\nFrom position 9: %s\n", buffer);
    fclose(fp);

    return 0;
}
